import { drizzle } from "drizzle-orm/node-postgres";
import { resolve } from "path";
import { config } from "dotenv";
import { Client } from "pg";

// Környezeti változók betöltése a .env fájlból
config({ path: resolve(process.cwd(), ".env") });

const connectionString = process.env.DATABASE_URL;

if (!connectionString) {
  throw new Error("❌ DATABASE_URL környezeti változó nincs beállítva a .env fájlban!");
}

async function main() {
  console.log("🔥 Adatbázis sémák törlése (DROP SCHEMA public CASCADE)...");
  
  const client = new Client({
    connectionString: connectionString,
  });

  try {
    await client.connect();
    // Eldobjuk a public sémát, majd újra létrehozzuk üresen
    await client.query('DROP SCHEMA public CASCADE;');
    await client.query('CREATE SCHEMA public;');
    
    console.log("✅ Adatbázis sémák sikeresen törölve és újratelepítve!");
  } catch (error) {
    console.error("❌ Hiba az adatbázis sémák törlésekor:", error);
    process.exit(1);
  } finally {
    await client.end();
  }
}

main();

import {
  pgTable,
  uuid,
  varchar,
  timestamp,
  text,
  pgEnum,
} from "drizzle-orm/pg-core";

// Enumok a jogosultságokhoz és címtípusokhoz
export const roleEnum = pgEnum("role", ["admin", "user"]);
export const addressTypeEnum = pgEnum("address_type", ["billing", "shipping"]);

export const users = pgTable("users", {
  id: uuid("id").defaultRandom().primaryKey(),
  email: varchar("email", { length: 255 }).notNull().unique(),
  passwordHash: varchar("password_hash", { length: 255 }).notNull(),
  role: roleEnum("role").default("user").notNull(),
  createdAt: timestamp("created_at").defaultNow().notNull(),
  updatedAt: timestamp("updated_at").defaultNow().notNull(),
});

export const profiles = pgTable("profiles", {
  id: uuid("id").defaultRandom().primaryKey(),
  userId: uuid("user_id")
    .references(() => users.id, { onDelete: "cascade" })
    .notNull(),
  name: varchar("name", { length: 255 }),
  phone: varchar("phone", { length: 50 }),
  lang: varchar("lang", { length: 10 }).default("hu").notNull(),
});

export const addresses = pgTable("addresses", {
  id: uuid("id").defaultRandom().primaryKey(),
  userId: uuid("user_id")
    .references(() => users.id, { onDelete: "cascade" })
    .notNull(),
  type: addressTypeEnum("type").notNull(),
  name: varchar("name", { length: 255 }).notNull(),
  zip: varchar("zip", { length: 20 }).notNull(),
  city: varchar("city", { length: 255 }).notNull(),
  street: varchar("street", { length: 255 }).notNull(),
  taxNumber: varchar("tax_number", { length: 50 }),
});

export const userAccess = pgTable("user_access", {
  id: uuid("id").defaultRandom().primaryKey(),
  userId: uuid("user_id")
    .references(() => users.id, { onDelete: "cascade" })
    .notNull(),
  category: varchar("category", { length: 100 }).notNull(), // pl. kurzus kategória
  level: varchar("level", { length: 50 }), // szint
  expiresAt: timestamp("expires_at"), // 60 napos hozzáféréshez
  createdAt: timestamp("created_at").defaultNow().notNull(),
});

"use server";

import { db } from "@/db";
import { products, productVariants, productMedia, productCategories, productRecommendations, productAttachments } from "@/db/schema/shop";
import { revalidatePath } from "next/cache";
import { z } from "zod";
import { createProductServerSchema, CreateProductPayload } from "./schemas";
import { eq } from "drizzle-orm";

// SEO-barát slug generáló a termék nevéből (hu alapján, vagy bármely elérhető nyelvből)
function generateSlug(name: Record<string, string>): string {
  const base = name.hu || name.en || name.sk || "termek";
  return base
    .toLowerCase()
    .normalize("NFD") // Ékezetek lebontása (á → a, é → e, stb.)
    .replace(/[\u0300-\u036f]/g, "") // Ékezetjelek eltávolítása
    .replace(/[^a-z0-9\s-]/g, "") // Csak betű, szám, szóköz, kötőjel marad
    .trim()
    .replace(/\s+/g, "-") // Szóközök → kötőjel
    .replace(/-+/g, "-"); // Dupla kötőjel összevonása
}

// Ha a slug már létezik, egyedi suffix hozzáadása (-2, -3, stb.)
async function ensureUniqueSlug(baseSlug: string): Promise<string> {
  let slug = baseSlug;
  let counter = 2;
  while (true) {
    const [existing] = await db
      .select({ id: products.id })
      .from(products)
      .where(eq(products.slug, slug))
      .limit(1);
    if (!existing) break;
    slug = `${baseSlug}-${counter}`;
    counter++;
  }
  return slug;
}

export async function createProduct(formData: CreateProductPayload) {
  try {
    // Szigorú szerveroldali validálás a központosított sémával
    const validated = createProductServerSchema.parse(formData);

    // Slug generálás a termék nevéből
    const baseSlug = generateSlug(validated.name as Record<string, string>);
    const slug = await ensureUniqueSlug(baseSlug);

    // Tranzakció indítása az inkonzisztenciák elkerülésére
    const result = await db.transaction(async (tx) => {
      // 1. Termék létrehozása a Products táblában (JSONB nevekkel és leírásokkal)
      const [newProduct] = await tx
        .insert(products)
        .values({
          slug, // Automatikusan generált SEO slug
          name: validated.name as Record<string, string>,
          description: validated.description as Record<string, string>,
          shortDescription: validated.shortDescription as Record<string, string>,
          longDescription: validated.longDescription as Record<string, string>,
          specifications: (validated.specifications || []) as any,
          type: validated.type,
          status: validated.status,
          priority: validated.priority,
          layoutTemplate: validated.layoutTemplate,
        })
        .returning();

      // 2. Variánsok létrehozása
      if (validated.variants && validated.variants.length > 0) {
        await tx.insert(productVariants).values(
          validated.variants.map((v) => ({
            productId: newProduct.id,
            name: v.name as Record<string, string>,
            sku: v.sku || `DIG-${Date.now()}-${Math.floor(Math.random() * 1000)}`,
            priceHuf: v.priceHuf,
            priceEur: v.priceEur.toString(),
            stock: v.stock || 0,
            weight: v.weight ? v.weight.toString() : null,
            width: v.width ? v.width.toString() : null,
            height: v.height ? v.height.toString() : null,
            depth: v.depth ? v.depth.toString() : null,
          }))
        );
      }

      // 3. Média mentése a Product Media táblába
      if (validated.media && validated.media.length > 0) {
        await tx.insert(productMedia).values(
          validated.media.map((m, index) => ({
            productId: newProduct.id,
            url: m.url,
            type: m.type as "IMAGE" | "YOUTUBE" | "AUDIO",
            order: index,
          }))
        );
      }

      // 4. Kategória hozzárendelések mentése
      if (validated.categoryIds && validated.categoryIds.length > 0) {
        await tx.insert(productCategories).values(
          validated.categoryIds.map((categoryId: string) => ({
            productId: newProduct.id,
            categoryId,
          }))
        );
      }

      // 5. Ajánlások mentése
      if (validated.recommendations && validated.recommendations.length > 0) {
        await tx.insert(productRecommendations).values(
          validated.recommendations.map((recId: string) => ({
            productId: newProduct.id,
            recommendedProductId: recId,
          }))
        );
      }

      // 6. Csatolmányok mentése
      if (validated.attachments && validated.attachments.length > 0) {
        await tx.insert(productAttachments).values(
          validated.attachments.map((att) => ({
            productId: newProduct.id,
            url: att.url,
            name: att.name,
          }))
        );
      }

      return newProduct;
    });

    // Sikeres mentés után újra-generáljuk az admin és a publikus termékoldalt
    revalidatePath("/admin/products");
    revalidatePath("/products");
    return { success: true, product: result };
    
  } catch (error) {
    console.error("Hiba a termék létrehozásakor:", error);
    if (error instanceof z.ZodError) {
       // Kinyerjük a validációs hibaüzenetet
      return { success: false, error: error.issues[0]?.message || "Validációs hiba" };
    }
    return { success: false, error: "Váratlan hiba történt az adatbázisba írás során." };
  }
}

export async function updateProduct(id: string, formData: CreateProductPayload) {
  try {
    const validated = createProductServerSchema.parse(formData);

    const result = await db.transaction(async (tx) => {
      // 1. Termék frissítése
      const [updatedProduct] = await tx
        .update(products)
        .set({
          name: validated.name as Record<string, string>,
          description: validated.description as Record<string, string>,
          shortDescription: validated.shortDescription as Record<string, string>,
          longDescription: validated.longDescription as Record<string, string>,
          specifications: (validated.specifications || []) as any,
          type: validated.type,
          status: validated.status,
          priority: validated.priority,
          layoutTemplate: validated.layoutTemplate,
        })
        .where(eq(products.id, id))
        .returning();

      // 2. Variánsok szinkronizálása (upsert / delete logika)
      const existingVariants = await tx.select().from(productVariants).where(eq(productVariants.productId, id));
      
      const payloadVarIds = validated.variants?.map((v) => v.id).filter(Boolean) || [];
      
      // Amik nincsenek a listában, azokat beszéljük / töröljük
      const variantsToDelete = existingVariants.filter(ev => !payloadVarIds.includes(ev.id));
      if (variantsToDelete.length > 0) {
         for (const vdel of variantsToDelete) {
           await tx.delete(productVariants).where(eq(productVariants.id, vdel.id));
         }
      }

      // Upsert
      if (validated.variants) {
        for (const v of validated.variants) {
          if (v.id) {
            await tx.update(productVariants)
              .set({
                name: v.name as Record<string, string>,
                sku: v.sku,
                priceHuf: v.priceHuf,
                priceEur: v.priceEur.toString(),
                stock: v.stock,
                weight: v.weight ? v.weight.toString() : null,
                width: v.width ? v.width.toString() : null,
                height: v.height ? v.height.toString() : null,
                depth: v.depth ? v.depth.toString() : null,
              })
              .where(eq(productVariants.id, v.id));
          } else {
            await tx.insert(productVariants).values({
              productId: id,
              name: v.name as Record<string, string>,
              sku: v.sku || `DIG-${Date.now()}-${Math.floor(Math.random() * 1000)}`,
              priceHuf: v.priceHuf,
              priceEur: v.priceEur.toString(),
              stock: v.stock || 0,
              weight: v.weight ? v.weight.toString() : null,
              width: v.width ? v.width.toString() : null,
              height: v.height ? v.height.toString() : null,
              depth: v.depth ? v.depth.toString() : null,
            });
          }
        }
      }

      // 3. Média szinkronizálása (Törlünk mindent és újra felvisszük az új sorrenddel)
      await tx.delete(productMedia).where(eq(productMedia.productId, id));

      if (validated.media && validated.media.length > 0) {
        await tx.insert(productMedia).values(
          validated.media.map((m, index) => ({
            productId: id,
            url: m.url,
            type: m.type as "IMAGE" | "YOUTUBE" | "AUDIO",
            order: index,
          }))
        );
      }

      // 4. Kategória szinkronizálása
      await tx.delete(productCategories).where(eq(productCategories.productId, id));
      if (validated.categoryIds && validated.categoryIds.length > 0) {
        await tx.insert(productCategories).values(
          validated.categoryIds.map((categoryId: string) => ({
            productId: id,
            categoryId,
          }))
        );
      }

      // 5. Ajánlások szinkronizálása
      await tx.delete(productRecommendations).where(eq(productRecommendations.productId, id));
      if (validated.recommendations && validated.recommendations.length > 0) {
        await tx.insert(productRecommendations).values(
          validated.recommendations.map((recId: string) => ({
            productId: id,
            recommendedProductId: recId,
          }))
        );
      }

      // 6. Csatolmányok szinkronizálása
      await tx.delete(productAttachments).where(eq(productAttachments.productId, id));
      if (validated.attachments && validated.attachments.length > 0) {
        await tx.insert(productAttachments).values(
          validated.attachments.map((att) => ({
            productId: id,
            url: att.url,
            name: att.name,
          }))
        );
      }

      return updatedProduct;
    });

    revalidatePath("/admin/products");
    revalidatePath("/products");
    revalidatePath(`/products/${result.slug}`);
    
    return { success: true, product: result };

  } catch (error) {
    console.error("Hiba a termék frissítésekor:", error);
    if (error instanceof z.ZodError) {
      return { success: false, error: error.issues[0]?.message || "Validációs hiba" };
    }
    return { success: false, error: "Váratlan hiba történt a módosítás során." };
  }
}

"use client";

import { useState } from "react";
import { Tabs, TabsContent, TabsList, TabsTrigger } from "@/components/ui/tabs";
import { ProductDetailItem } from "@/modules/shop/queries";
import { FileText, List } from "lucide-react";

interface ProductContentProps {
  product: ProductDetailItem;
  lang?: "hu" | "en" | "sk";
}

export function ProductContent({ product, lang = "hu" }: ProductContentProps) {
  const [activeTab, setActiveTab] = useState<string>("description");

  // A nyelv szerinti szöveg kiszedése, ha nincs, fallback az első elérhető nyelvre vagy üres stringre
  const getLocalizedText = (jsonbMap: Record<string, string> | null) => {
    if (!jsonbMap) return "";
    return jsonbMap[lang] || jsonbMap["hu"] || Object.values(jsonbMap)[0] || "";
  };

  const description = getLocalizedText(product.description);
  
  // A specs lehet szimpla key-value (string: string) vagy komplexebb JSON.
  // Megpróbáljuk Record<string, string>-ként kezelni a kiírást egy táblázatban.
  const hasSpecs = product.specifications && Object.keys(product.specifications).length > 0;

  return (
    <div className="mt-12 rounded-xl border bg-card text-card-foreground shadow-sm overflow-hidden">
      <Tabs value={activeTab} onValueChange={setActiveTab} className="w-full">
        <TabsList className="w-full justify-start rounded-none border-b bg-muted/50 p-0 h-14">
          <TabsTrigger 
            value="description" 
            className="rounded-none h-full data-[state=active]:border-b-2 data-[state=active]:border-primary data-[state=active]:shadow-none px-6 font-medium"
          >
            <FileText className="w-4 h-4 mr-2" />
            Részletes Leírás
          </TabsTrigger>
          {hasSpecs && (
            <TabsTrigger 
              value="specs" 
              className="rounded-none h-full data-[state=active]:border-b-2 data-[state=active]:border-primary data-[state=active]:shadow-none px-6 font-medium"
            >
              <List className="w-4 h-4 mr-2" />
              Specifikációk
            </TabsTrigger>
          )}
        </TabsList>
        
        <div className="p-6 sm:p-8">
          <TabsContent value="description" className="m-0 focus-visible:outline-none focus-visible:ring-0">
            {description ? (
              <div 
                className="prose prose-slate dark:prose-invert max-w-none prose-p:leading-relaxed prose-a:text-primary whitespace-pre-wrap"
                // Ha a jövőben Rich Text Editort használnak, itt dangerouslySetInnerHTML is lehet, de most sima string:
                dangerouslySetInnerHTML={{ __html: description }}
              />
            ) : (
              <p className="text-muted-foreground italic">
                Nincs elérhető leírás ehhez a termékhez {lang.toUpperCase()} nyelven.
              </p>
            )}
          </TabsContent>

          {hasSpecs && (
            <TabsContent value="specs" className="m-0 focus-visible:outline-none focus-visible:ring-0">
              <div className="rounded-md border">
                <table className="w-full text-sm text-left">
                  <tbody className="divide-y divide-border">
                    {Object.entries(product.specifications as Record<string, any>).map(([key, val], idx) => (
                      <tr key={idx} className="hover:bg-muted/50 transition-colors">
                        <td className="w-1/3 py-3 px-4 font-medium text-muted-foreground border-r bg-muted/20">
                          {key}
                        </td>
                        <td className="py-3 px-4">
                          {typeof val === 'object' ? JSON.stringify(val) : String(val)}
                        </td>
                      </tr>
                    ))}
                  </tbody>
                </table>
              </div>
            </TabsContent>
          )}
        </div>
      </Tabs>
    </div>
  );
}

"use client";

import { useState, useEffect, useRef } from "react";
import Image from "next/image";
import { useFieldArray } from "react-hook-form";
import { useProductForm, ProductFormValues } from "../hooks/use-product-form";
import { Button } from "@/components/ui/button";
import {
  Form,
  FormControl,
  FormField,
  FormItem,
  FormLabel,
  FormMessage,
} from "@/components/ui/form";
import { Input } from "@/components/ui/input";
import { Tabs, TabsContent, TabsList, TabsTrigger } from "@/components/ui/tabs";
import { Card, CardContent, CardHeader, CardTitle } from "@/components/ui/card";

import {
  Select,
  SelectContent,
  SelectItem,
  SelectTrigger,
  SelectValue,
} from "@/components/ui/select";
import { Switch } from "@/components/ui/switch";
import { Textarea } from "@/components/ui/textarea";
import { Checkbox } from "@/components/ui/checkbox";
import { Loader2 } from "lucide-react";

interface PendingUpload {
  file: File;
  localUrl: string;
  type: "IMAGE" | "AUDIO" | "DOCUMENT";
}

export function ProductForm({ categories = [], products = [] }: { categories?: { id: string, name: Record<string, string> }[], products?: { id: string, name: Record<string, string> }[] }) {
  const { form, isPending, onSubmit, productType, moveMedia, removeMedia } = useProductForm();
  
  const { fields: variantFields, append: appendVariant, remove: removeVariant } = useFieldArray({
    control: form.control,
    name: "variants",
  });

  const { fields: specFields, append: appendSpec, remove: removeSpec } = useFieldArray({
    control: form.control,
    name: "specifications",
  });

  const { fields: attachmentFields, append: appendAttachment, remove: removeAttachment } = useFieldArray({
    control: form.control,
    name: "attachments",
  });
  
  const [pendingUploads, setPendingUploads] = useState<PendingUpload[]>([]);
  const objectUrlsRef = useRef<Set<string>>(new Set());

  // Cleanup memory on unmount for object URLs
  useEffect(() => {
    return () => {
      objectUrlsRef.current.forEach(url => URL.revokeObjectURL(url));
    };
  }, []);

  const handleFileUpload = async (e: React.ChangeEvent<HTMLInputElement>, type: "IMAGE" | "AUDIO" | "DOCUMENT") => {
    const files = Array.from(e.target.files || []);
    if (files.length === 0) return;

    // 1. Generate local previews
    const newPending = files.map(file => {
      const url = URL.createObjectURL(file);
      objectUrlsRef.current.add(url);
      return {
        file,
        localUrl: url,
        type
      };
    });

    setPendingUploads(prev => [...prev, ...newPending]);

    try {
      const uploadPromises = newPending.map(async (item) => {
        const formData = new FormData();
        formData.append("file", item.file);
        const res = await fetch("/api/upload", { method: "POST", body: formData });
        const data = await res.json();
        
        // Cleanup local URL when done
        URL.revokeObjectURL(item.localUrl);
        return { url: data.url as string, type: item.type, localUrl: item.localUrl };
      });

      const uploadedResults = await Promise.all(uploadPromises);
      
      // Remove from pending
      setPendingUploads(prev => prev.filter(p => !newPending.find(np => np.localUrl === p.localUrl)));

      // Add to final form state
      const newMediaItems = uploadedResults.filter(res => res.url && res.type !== "DOCUMENT").map(res => ({ url: res.url, type: res.type as "IMAGE" | "AUDIO" | "YOUTUBE" }));
      if (newMediaItems.length > 0) {
        const currentMedia = form.getValues("media") || [];
        form.setValue("media", [...currentMedia, ...newMediaItems]);
      }

      // Add to attachments
      const newAttachments = uploadedResults.filter(res => res.url && res.type === "DOCUMENT");
      newAttachments.forEach(att => {
        const fileObj = newPending.find(p => p.localUrl === att.localUrl)?.file;
        appendAttachment({ url: att.url, name: fileObj?.name || "Dokumentum" });
      });
      
    } catch(err) {
      console.error(err);
      newPending.forEach(item => URL.revokeObjectURL(item.localUrl));
      setPendingUploads(prev => prev.filter(p => !newPending.find(np => np.localUrl === p.localUrl)));
    } finally {
      e.target.value = "";
    }
  };

  const currentMedia = form.watch("media") || [];

  return (
    <Card className="w-full max-w-2xl mx-auto">
      <CardHeader>
        <CardTitle>Új termék hozzáadása</CardTitle>
      </CardHeader>
      <CardContent>
        <Form {...form}>
          <form onSubmit={form.handleSubmit(onSubmit)} className="space-y-6">
            <div className="grid grid-cols-1 md:grid-cols-2 gap-4">
              <FormField
                control={form.control}
                name="type"
                render={({ field }) => (
                  <FormItem>
                    <FormLabel>Termék típusa</FormLabel>
                    <Select onValueChange={field.onChange} defaultValue={field.value}>
                      <FormControl>
                        <SelectTrigger>
                          <SelectValue placeholder="Válassz típust" />
                        </SelectTrigger>
                      </FormControl>
                      <SelectContent>
                        <SelectItem value="physical">Fizikai termék</SelectItem>
                        <SelectItem value="digital">Digitális termék (LMS)</SelectItem>
                      </SelectContent>
                    </Select>
                    <FormMessage />
                  </FormItem>
                )}
              />
              <FormField
                 control={form.control}
                 name="status"
                 render={({ field }) => (
                   <FormItem className="flex flex-row items-center justify-between rounded-lg border p-4 h-full shadow-sm">
                     <div className="space-y-0.5">
                       <FormLabel className="text-base">Láthatóság</FormLabel>
                       <p className="text-xs text-muted-foreground">Aktív termékek jelennek meg a boltban.</p>
                     </div>
                     <FormControl>
                       <Switch 
                         checked={field.value === "ACTIVE"} 
                         onCheckedChange={(c) => field.onChange(c ? "ACTIVE" : "INACTIVE")} 
                       />
                     </FormControl>
                   </FormItem>
                 )}
              />
            </div>

            {categories.length > 0 && (
              <FormField
                control={form.control}
                name="categoryIds"
                render={() => (
                  <FormItem className="border rounded-lg p-4 shadow-sm">
                    <div className="mb-4">
                      <FormLabel className="text-base">Kategóriák</FormLabel>
                    </div>
                    <div className="grid grid-cols-2 md:grid-cols-4 gap-4">
                      {categories.map((category) => (
                        <FormField
                          key={category.id}
                          control={form.control}
                          name="categoryIds"
                          render={({ field }) => {
                            return (
                              <FormItem key={category.id} className="flex flex-row items-start space-x-3 space-y-0">
                                <FormControl>
                                  <Checkbox
                                    checked={field.value?.includes(category.id)}
                                    onCheckedChange={(checked) => {
                                      return checked
                                        ? field.onChange([...(field.value || []), category.id])
                                        : field.onChange((field.value?.filter((value: string) => value !== category.id)) || [])
                                    }}
                                  />
                                </FormControl>
                                <FormLabel className="font-normal cursor-pointer">
