"use client";

import { useState } from "react";
import { useForm } from "react-hook-form";
import { zodResolver } from "@hookform/resolvers/zod";
import * as z from "zod";
import { toast } from "sonner";
import { createProduct } from "../actions";
import { productFormSchema } from "../schemas";

export type ProductFormValues = z.infer<typeof productFormSchema>;

export function useProductForm() {
  const [isPending, setIsPending] = useState(false);

  const form = useForm<ProductFormValues>({
    // Ts-ignore a React Hook Form és Zod types inkompatibilitás miatt transzformációknál
    // eslint-disable-next-line @typescript-eslint/no-explicit-any
    resolver: zodResolver(productFormSchema) as any,
    defaultValues: {
      type: "physical",
      name_hu: "",
      name_en: "",
      description_hu: "",
      description_en: "",
      description_sk: "",
      shortDescription_hu: "",
      shortDescription_en: "",
      shortDescription_sk: "",
      longDescription_hu: "",
      longDescription_en: "",
      longDescription_sk: "",
      variants: [{
        sku: "",
        priceHuf: 0,
        priceEur: 0,
        stock: 0,
        weight: 0,
        width: 0,
        height: 0,
        depth: 0,
      }],
      specifications: [],
      recommendations: [],
      attachments: [],
      media: [],
      status: "ACTIVE",
      priority: 0,
      layoutTemplate: "STANDARD",
      categoryIds: [],
    },
  });

  const productType = form.watch("type");

  async function onSubmit(values: ProductFormValues) {
    setIsPending(true);
    
    // Transzformáció a szerver action által várt formátumra
    const payload = {
      type: values.type,
      name: {
        hu: values.name_hu,
        en: values.name_en || "",
        sk: values.name_sk || "",
      },
      description: {
        hu: values.description_hu || "",
        en: values.description_en || "",
        sk: values.description_sk || "",
      },
      shortDescription: {
        hu: values.shortDescription_hu || "",
        en: values.shortDescription_en || "",
        sk: values.shortDescription_sk || "",
      },
      longDescription: {
        hu: values.longDescription_hu || "",
        en: values.longDescription_en || "",
        sk: values.longDescription_sk || "",
      },
      variants: values.variants.map(v => ({
        id: v.id,
        name: {
          hu: v.name_hu || "",
          en: v.name_en || "",
          sk: v.name_sk || "",
        },
        sku: v.sku,
        priceHuf: v.priceHuf,
        priceEur: v.priceEur,
        stock: v.stock,
        weight: v.weight,
        width: v.width,
        height: v.height,
        depth: v.depth,
      })),
      specifications: values.specifications,
      recommendations: values.recommendations,
      attachments: values.attachments,
      media: values.media,
      status: values.status,
      priority: values.priority,
      layoutTemplate: values.layoutTemplate,
      categoryIds: values.categoryIds || [],
    };

    const result = await createProduct(payload);
    setIsPending(false);

    if (result.success) {
      toast.success("Termék sikeresen létrehozva!");
      form.reset();
    } else {
      toast.error(result.error || "Hiba történt a mentés során.");
    }
  }

  const moveMedia = (index: number, direction: 'UP' | 'DOWN') => {
    const currentMedia = [...(form.getValues("media") || [])];
    if (direction === 'UP' && index > 0) {
      const temp = currentMedia[index - 1];
      currentMedia[index - 1] = currentMedia[index];
      currentMedia[index] = temp;
      form.setValue("media", currentMedia, { shouldDirty: true });
    } else if (direction === 'DOWN' && index < currentMedia.length - 1) {
      const temp = currentMedia[index + 1];
      currentMedia[index + 1] = currentMedia[index];
      currentMedia[index] = temp;
      form.setValue("media", currentMedia, { shouldDirty: true });
    }
  };

  const removeMedia = (index: number) => {
    const currentMedia = form.getValues("media") || [];
    currentMedia.splice(index, 1);
    form.setValue("media", [...currentMedia], { shouldDirty: true });
  };

  return { form, isPending, onSubmit, productType, moveMedia, removeMedia };
}

import { db } from "@/db";
import { products, productVariants, productMedia, productCategories, categories, productRecommendations, productAttachments } from "@/db/schema";
import { eq, ilike, and, sql, inArray, asc } from "drizzle-orm";

export type ProductListFilters = {
  search?: string;
  type?: "physical" | "digital";
  categoryId?: string;
};

// Visszaérkező típus a UI-hoz
export type ProductListItem = {
  id: string;
  slug: string; // SEO-barát URL azonosító
  name: Record<string, string>; // JSONB többnyelvű név { hu: string, en: string, ... }
  description: Record<string, string> | null;
  type: "physical" | "digital";
  minPriceHuf: number | null;
  minPriceEur: number | null;
  mainImageUrl: string | null;
  categories: { id: string; name: Record<string, string>; slug: string }[];
};

export async function getActiveProducts(filters?: ProductListFilters): Promise<ProductListItem[]> {
  // A keresési és szűrési feltételek tömbje
  const conditions = [];

  if (filters?.search) {
    const term = `%${filters.search}%`;
    conditions.push(
      sql`${products.name}->>'hu' ILIKE ${term} OR ${products.name}->>'en' ILIKE ${term} OR ${products.name}->>'sk' ILIKE ${term}`
    );
  }

  if (filters?.type) {
    conditions.push(eq(products.type, filters.type));
  }

  if (filters?.categoryId) {
    const categoryProductsSq = db
      .select({ productId: productCategories.productId })
      .from(productCategories)
      .where(eq(productCategories.categoryId, filters.categoryId));
      
    conditions.push(inArray(products.id, categoryProductsSq));
  }

  // Alap lekérdezés + Feltételek
  let baseQuery = db
    .select({
      id: products.id,
      slug: products.slug,
      name: products.name,
      description: products.description,
      type: products.type,
      minPriceHuf: sql<number>`min(${productVariants.priceHuf})`.mapWith(Number),
      minPriceEur: sql<number>`min(${productVariants.priceEur})`.mapWith(Number),
      mainImageUrl: sql<string>`min(${productMedia.url})` 
    })
    .from(products)
    .leftJoin(productVariants, eq(products.id, productVariants.productId))
    .leftJoin(productMedia, eq(products.id, productMedia.productId));

  if (conditions.length > 0) {
    baseQuery = baseQuery.where(and(...conditions)) as any;
  }
  
  // Futtatás (a groupBy-t is figyelembe véve)
  const rawResults = await (baseQuery.groupBy(products.id) as any);

  // Most lekérjük az összes érintett termék kategóriáját Map-be
  const productIds = rawResults.map((r: any) => r.id);
  const categoriesMap = new Map<string, { id: string; name: Record<string, string>; slug: string }[]>();

  if (productIds.length > 0) {
    const rawCategories = await db
      .select({
        productId: productCategories.productId,
        category: categories,
      })
      .from(productCategories)
      .innerJoin(categories, eq(productCategories.categoryId, categories.id))
      .where(inArray(productCategories.productId, productIds));

    for (const row of rawCategories) {
      const existing = categoriesMap.get(row.productId) || [];
      // eslint-disable-next-line @typescript-eslint/no-explicit-any
      existing.push(row.category as any);
      categoriesMap.set(row.productId, existing);
    }
  }

  // Formázás és visszatérés
  return rawResults.map((r: any) => ({
    ...r,
    name: r.name as Record<string, string>,
    description: r.description as Record<string, string> | null,
    categories: categoriesMap.get(r.id) || [],
  }));
}

